const indexInput2 = new Map();

for (const item of input2) {
  const row2 = item.json || {};
  const chave2 = makeKeyFromInput2(row2);

  if (!chave2.chave || chave2.chave === "♦♦") continue;

  if (!indexInput2.has(chave2.chave)) {
    indexInput2.set(chave2.chave, []);
  }

  indexInput2.get(chave2.chave).push({
    row: row2,
    chaves: chave2
  });
}

const output = [];

// ======================================================
// PERCORRE INPUT1 E RETORNA SOMENTE OS QUE NÃO DERAM MATCH
// ======================================================
for (const item of input1) {
  const row1 = item.json || {};
  const chave1 = makeKeyFromInput1(row1);

  if (!chave1.chave || chave1.chave === "♦♦") continue;

  const matchesInput2 = indexInput2.get(chave1.chave) || [];
  const teveMatch = matchesInput2.length > 0;

  if (!teveMatch) {
    output.push({
      json: {
        teveMatch: false,
        motivo: "Registro existe no input1, mas não foi encontrado no input2",

        // Chave completa usada no match
        chaveMatch: chave1.chave,

        // Chaves separadas do input1
        input1_chave_data: chave1.data,
        input1_chave_codigo: chave1.codigo,
        input1_chave_exame: chave1.exame,
        input1_chave_completa: chave1.chave,

        // Chaves do input2 vazias, pois não houve match
        input2_chave_data: "",
        input2_chave_codigo: "",
        input2_chave_exame: "",
        input2_chave_completa: "",

        // Dados originais do input1 com prefixo
        ...Object.fromEntries(
          Object.entries(row1).map(([k, v]) => [`input1_${k}`, v])
        )
      }
    });
  }
}

// ======================================================
// SE TODOS DO INPUT1 DERAM MATCH
// ======================================================
if (output.length === 0) {
  return [
    {
      json: {
        teveMatch: true,
        mensagem: "Todos os registros do input1 deram match com o input2"
      }
    }
  ];
}

return output;

// =======================================================
// LABOVIDA Pendências OCR -> JSON estruturado
// Entrada aceita:
// - $json.extractedText
// - $json.pages[].markdown
// - $json.markdown
// - $json.text
// - ou array vindo em $input
// =======================================================

const itensEntrada = $input.all().map(item => item.json);

// =======================================================
// 1) Junta todo o texto OCR recebido
// =======================================================
function obterTextoOCR(json) {
  if (!json) return "";

  if (json.extractedText) {
    return String(json.extractedText);
  }

  if (Array.isArray(json.pages)) {
    return json.pages
      .map(p => p.markdown || p.text || "")
      .filter(Boolean)
      .join("\n");
  }

  if (json.markdown) {
    return String(json.markdown);
  }

  if (json.text) {
    return String(json.text);
  }

  return "";
}

let textoCompleto = "";

for (const item of itensEntrada) {
  // Caso venha como array dentro do primeiro item
  if (Array.isArray(item)) {
    for (const sub of item) {
      textoCompleto += "\n" + obterTextoOCR(sub);
    }
  } else {
    textoCompleto += "\n" + obterTextoOCR(item);
  }
}

textoCompleto = String(textoCompleto || "")
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/\u00A0/g, " ")
  .replace(/[ \t]+/g, " ")
  .trim();

// =======================================================
// 2) Funções auxiliares
// =======================================================
function limparCampo(valor) {
  return String(valor || "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizarExame(exame) {
  return String(exame || "")
    .replace(/\s+/g, "")
    .replace(/\(\s+/g, "(")
    .replace(/\s+\)/g, ")")
    .trim()
    .toUpperCase();
}

// Captura exames no padrão:
// B12(LIB), T4L(LIB), 25OHD(LIB), COAGU(6), HB1AC(6)
// E também exames incompletos no final, como TGP
function extrairExames(texto) {
  const s = String(texto || "")
    .replace(/\s+/g, " ")
    .trim();

  const exames = [];

  // Exames com parênteses
  const regexComParen = /\b[A-Z0-9]{1,12}\s*\(\s*(?:LIB|6)\s*\)/gi;
  let match;

  while ((match = regexComParen.exec(s)) !== null) {
    exames.push(normalizarExame(match[0]));
  }

  // Remove exames já encontrados para checar se sobrou exame sem parênteses
  let restante = s.replace(regexComParen, " ").replace(/\s+/g, " ").trim();

  // Lista de exames conhecidos que às vezes vêm quebrados sem (LIB)
  const examesConhecidosSemParen = [
    "TGP", "TGO", "GLIS", "HEMO", "CRE", "URE", "SU", "B12",
    "T4L", "TSH", "PCR", "CA", "GGT", "IONO", "HP", "CTFT",
    "HB1AC", "FE", "TAP", "BHCG", "URICU", "COAGU", "VSH"
  ];

  for (const ex of examesConhecidosSemParen) {
    const re = new RegExp(`\\b${ex}\\b`, "i");
    if (re.test(restante) && !exames.includes(ex)) {
      exames.push(ex);
    }
  }

  return exames;
}

function montarObjetoExames(lista) {
  const obj = {};

  lista.forEach((exame, index) => {
    obj[`ex${index + 1}`] = exame;
  });

  return obj;
}

// =======================================================
// 3) Extrai linhas da tabela
// =======================================================
const linhas = textoCompleto
  .split("\n")
  .map(l => limparCampo(l))
  .filter(Boolean);

// =======================================================
// 4) Processa registros
// =======================================================
const registros = [];
const chavesVistas = new Set();

for (const linhaOriginal of linhas) {
  let linha = linhaOriginal;

  // Ignora cabeçalhos e separadores
  if (/^LABOVIDA$/i.test(linha)) continue;
  if (/Bancada/i.test(linha)) continue;
  if (/Relat[oó]rio de Pend[eê]ncias/i.test(linha)) continue;
  if (/Data de impress[aã]o/i.test(linha)) continue;
  if (/Usu[aá]rio/i.test(linha)) continue;
  if (/^\|\s*-+/.test(linha)) continue;
  if (/^\|\s*---/.test(linha)) continue;

  // Só processa linhas que começam com tabela:
  // | 3 | 115 | 07/04/2026 | 11540927 | ...
  if (!/^\|\s*\d+\s*\|\s*\d+\s*\|\s*\d{2}\/\d{2}\/\d{4}\s*\|\s*\d+/.test(linha)) {
    continue;
  }

  // Remove primeira e última barra da tabela
  linha = linha.replace(/^\|/, "").replace(/\|$/, "").trim();

  const partes = linha
    .split("|")
    .map(p => limparCampo(p));

  if (partes.length < 5) continue;

  const areaRaw = partes[0];
  const postoRaw = partes[1];
  const dataCadastro = partes[2];
  const registroCadastro = String(partes[3] || "").replace(/\D/g, "");

  let nomePaciente = limparCampo(partes[4]);
  let textoExames = limparCampo(partes.slice(5).join(" "));

  // =====================================================
  // Caso OCR coloque exames junto com o nome, exemplo:
  // WILLIAM DOUGLAS PEREIRA DA SILVA CSURE(LIB) EXDIP(LIB)
  // =====================================================
  const posPrimeiroExameNoNome = nomePaciente.search(/\b[A-Z0-9]{1,12}\s*\(\s*(?:LIB|6)\s*\)/i);

  if (posPrimeiroExameNoNome !== -1) {
    const parteNome = nomePaciente.slice(0, posPrimeiroExameNoNome).trim();
    const parteExames = nomePaciente.slice(posPrimeiroExameNoNome).trim();

    nomePaciente = limparCampo(parteNome);
    textoExames = limparCampo(`${parteExames} ${textoExames}`);
  }

  const examesLista = extrairExames(textoExames);

  const area = Number(areaRaw);
  const posto = Number(postoRaw);

  if (!area || !posto || !dataCadastro || !registroCadastro || !nomePaciente) {
    continue;
  }

  const chave = [
    area,
    posto,
    dataCadastro,
    registroCadastro,
    nomePaciente
  ].join("|");

  if (chavesVistas.has(chave)) {
    continue;
  }

  chavesVistas.add(chave);

  registros.push({
    area,
    posto,
    dataCadastro,
    registroCadastro,
    nomePaciente,
    exame: montarObjetoExames(examesLista)
  });
}

// =======================================================
// 5) Retorno final: um item por paciente
// =======================================================
return registros.map((registro, index) => ({
  json: {
    ...registro,
    _idx: index + 1,
    _totalRegistros: registros.length
  }
}));

// ======================================================
// MATCH por 3 chaves
// ✅ Retorna SOMENTE os itens do INPUT1 que deram match com INPUT2
// ✅ Retorna todas as chaves dos dois inputs
// ======================================================

const norm = (v) =>
  String(v ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();

function extrairDataBR(valor) {
  if (!valor) return "";

  const texto = String(valor).trim();

  // Pega data no formato DD/MM/AAAA
  const m = texto.match(/\b(\d{2}\/\d{2}\/\d{4})\b/);

  return m ? m[1] : texto;
}

// ======================================================
// CHAVE INPUT 1
// Campos esperados:
// dataCadastro
// registroCadastro
// sigla
// ======================================================
function makeKeyFromInput1(row) {
  const data = norm(extrairDataBR(row["dataCadastro"]));
  const codigo = norm(row["registroCadastro"]);
  const exame = norm(row["exameUnico"]);

  return {
    data,
    codigo,
    exame,
    chave: `${data}♦${codigo}♦${exame}`
  };
}

// ======================================================
// CHAVE INPUT 2
// Campos esperados:
// Data do Cadastro
// Registro do Paciente
// SIGLA
// ======================================================
function makeKeyFromInput2(row) {
  const data = norm(extrairDataBR(row["Data do Cadastro"]));
  const codigo = norm(row["Registro do Paciente"]);
  const exame = norm(row["SIGLA"]);

  return {
    data,
    codigo,
    exame,
    chave: `${data}♦${codigo}♦${exame}`
  };
}

const input1 = $input.all(0);
const input2 = $input.all(1);

// ======================================================
// INDEXA INPUT2 PELA CHAVE
// ======================================================
const indexInput2 = new Map();

for (const item of input2) {
  const row2 = item.json || {};
  const chave2 = makeKeyFromInput2(row2);

  if (!chave2.chave || chave2.chave === "♦♦") continue;

  if (!indexInput2.has(chave2.chave)) {
    indexInput2.set(chave2.chave, []);
  }

  indexInput2.get(chave2.chave).push({
    row: row2,
    chaves: chave2
  });
}

const output = [];

// ======================================================
// PERCORRE INPUT1 E RETORNA SOMENTE OS QUE DERAM MATCH
// ======================================================
for (const item of input1) {
  const row1 = item.json || {};
  const chave1 = makeKeyFromInput1(row1);

  if (!chave1.chave || chave1.chave === "♦♦") continue;

  const matchesInput2 = indexInput2.get(chave1.chave) || [];

  if (matchesInput2.length > 0) {
    for (const match of matchesInput2) {
      output.push({
        json: {
          teveMatch: true,

          // Chave completa usada no match
          chaveMatch: chave1.chave,

          // Chaves separadas do input1
          input1_chave_data: chave1.data,
          input1_chave_codigo: chave1.codigo,
          input1_chave_exame: chave1.exame,
          input1_chave_completa: chave1.chave,

          // Chaves separadas do input2
          input2_chave_data: match.chaves.data,
          input2_chave_codigo: match.chaves.codigo,
          input2_chave_exame: match.chaves.exame,
          input2_chave_completa: match.chaves.chave,

          // Dados originais do input1 com prefixo
          ...Object.fromEntries(
            Object.entries(row1).map(([k, v]) => [`input1_${k}`, v])
          ),

          // Dados originais do input2 com prefixo
          ...Object.fromEntries(
            Object.entries(match.row).map(([k, v]) => [`input2_${k}`, v])
          )
        }
      });
    }
  }
}

// ======================================================
// SE NÃO HOUVER MATCH
// ======================================================
if (output.length === 0) {
  return [
    {
      json: {
        teveMatch: false,
        mensagem: "Nenhum item do input1 deu match com o input2"
      }
    }
  ];
}

return output;
